// === CALCULATOR CODE ===

const calculator = {
  // Electricity rate assumption ($/kWh)
  ELECTRICITY_RATE: 0.14,

  // Performance ratio (derating factor)
  PERFORMANCE_RATIO: 0.8,

  // Cost per watt by panel type (in $/W)
  COST_PER_WATT: {
    monocrystalline: 3.0,
    polycrystalline: 2.7,
    thin_film: 2.5
  },

  // Battery backup fixed cost
  BATTERY_COST: 8000,

  calculate(inputs) {
    // Validate first
    const validation = this.validate(inputs);
    if (validation.error) {
      return validation;
    }

    // Extract validated fields
    const { monthlyElectricBill, sunHoursPerDay, panelType, batteryBackup } = validation;

    // Compute monthly kWh
    const monthlyKwh = monthlyElectricBill / this.ELECTRICITY_RATE;
    const dailyKwh = monthlyKwh / 30;

    // System size in kW
    const systemSizeKw = dailyKwh / (sunHoursPerDay * this.PERFORMANCE_RATIO);

    // Cost per watt
    const costPerWatt = this.COST_PER_WATT[panelType];

    // Installation cost ($)
    const installationCost = systemSizeKw * 1000 * costPerWatt;

    // Battery cost
    const batteryCost = batteryBackup ? this.BATTERY_COST : 0;

    // Total cost
    const total = installationCost + batteryCost;

    // Annual savings assuming system offsets entire bill
    const annualSavings = monthlyElectricBill * 12;

    // Payback period in years
    const paybackYears = total / annualSavings;

    return {
      total: total,
      breakdown: {
        systemSizeKw: systemSizeKw,
        costPerWatt: costPerWatt,
        installationCost: installationCost,
        batteryCost: batteryCost,
        annualSavings: annualSavings,
        paybackYears: paybackYears,
        monthlyKwh: monthlyKwh,
        dailyKwh: dailyKwh
      }
    };
  },

  validate(inputs) {
    const errors = [];

    // --- monthlyElectricBill ---
    const bill = inputs.monthlyElectricBill;
    if (typeof bill !== 'number' || isNaN(bill) || bill <= 0) {
      errors.push("Monthly electric bill must be a positive number");
    }

    // --- sunHoursPerDay ---
    const sun = inputs.sunHoursPerDay;
    if (typeof sun !== 'number' || isNaN(sun) || sun <= 0) {
      errors.push("Sun hours per day must be greater than 0");
    }

    // --- panelType (case-insensitive, trim, normalize) ---
    let rawType = inputs.panelType;
    if (typeof rawType !== 'string') {
      errors.push("Invalid panel type");
    } else {
      rawType = rawType.trim().toLowerCase();
      if (!this.COST_PER_WATT.hasOwnProperty(rawType)) {
        errors.push("Invalid panel type");
      }
    }

    // --- batteryBackup must be real boolean ---
    let battery = inputs.batteryBackup;
    if (typeof battery !== 'boolean') {
      errors.push("Battery backup must be a boolean");
    }

    if (errors.length > 0) {
      return { error: errors.join("; ") };
    }

    // Return normalized clean object
    return {
      monthlyElectricBill: bill,
      sunHoursPerDay: sun,
      panelType: rawType.toLowerCase(), // already lowercased
      batteryBackup: battery
    };
  },

  formatCurrency(amount) {
    return '$' + amount.toFixed(2);
  }
};

// CALC_PARAMS for UI rendering
const CALC_PARAMS = [
  { name: 'monthlyElectricBill', label: 'Monthly Electric Bill ($)', type: 'number', placeholder: 'e.g. 150' },
